You can use the following Python code to check if a century year is a leap year:
python
def is_century_leap_year(year):
    if year % 400 == 0:
        return True
    elif year % 100 == 0:
        return False
    else:
        return False

# Example usage:
print(is_century_leap_year(2000))  # Output: True (leap year)
print(is_century_leap_year(2100))  # Output: False (common year)
